/**
 * Agent Task Auto-Register — PostToolUse[Agent] Hook
 *
 * After an Agent tool call succeeds, checks if a task was registered
 * for this agent. If not, auto-registers it in the local task registry
 * and injects a context nudge suggesting the model create a proper
 * TaskCreate for tracking.
 *
 * Complements the PreToolUse task-existence-gate (which warns/blocks
 * BEFORE spawn) by recording what actually launched AFTER spawn.
 *
 * This closes the "subagent orphaning" gap where agents run without
 * any task tracking, making progress invisible to the user.
 *
 * CC 2.1.9 Compliant: Uses outputWithContext for advisory nudge
 */

import type { HookInput, HookResult, HookContext } from '../../types.js';
import { outputSilentSuccess, outputWithContext, getField } from '../../lib/common.js';
import {
  getTaskByAgent,
  registerTask,
  generateTaskCreateInstruction,
} from '../../lib/task-integration.js';
import { NOOP_CTX } from '../../lib/context.js';

const HOOK_NAME = 'agent-task-auto-register';

/**
 * Agent types exempt from auto-registration.
 * Lightweight/exploratory agents that don't need task tracking.
 */
const EXEMPT_AGENTS = new Set([
  'Explore',
  'general-purpose',
  'Plan',
  'claude-code-guide',
  'statusline-setup',
]);

/**
 * Extract agent metadata from PostToolUse input.
 */
function extractAgentInfo(input: HookInput): {
  subagentType: string;
  description: string;
  name: string;
  background: boolean;
} {
  const subagentType = String(getField(input, 'subagent_type') || '');
  const description = String(getField(input, 'description') || '');
  const name = String(getField(input, 'name') || '');
  const background = input.tool_input?.run_in_background === true ||
    input.tool_input?.run_in_background === 'true';
  return { subagentType, description, name, background };
}

/**
 * PostToolUse hook: auto-register agent tasks after successful spawn.
 */
export function agentTaskAutoRegister(input: HookInput, ctx: HookContext = NOOP_CTX): HookResult {
  const { subagentType, description, name, background } = extractAgentInfo(input);

  if (!subagentType) {
    return outputSilentSuccess();
  }

  // Exempt lightweight agents
  if (EXEMPT_AGENTS.has(subagentType)) {
    ctx.log(HOOK_NAME, `Exempt: ${subagentType}`);
    return outputSilentSuccess();
  }

  // Check if task already registered (PreToolUse gate or skill already created one)
  const existing = getTaskByAgent(subagentType);
  if (existing) {
    ctx.log(HOOK_NAME, `Task already registered for ${subagentType}: ${existing.taskId}`);
    return outputSilentSuccess();
  }

  // Auto-register in local registry for pipeline tracking
  const autoId = `auto-${subagentType}-${Date.now()}`;
  const instruction = generateTaskCreateInstruction(subagentType, description, 0);

  registerTask(autoId, subagentType, 0);
  ctx.log(HOOK_NAME, `Auto-registered task ${autoId} for ${subagentType}`);

  // Nudge model to create a proper CC task (if not background/fire-and-forget)
  if (background) {
    return outputSilentSuccess();
  }

  const agentLabel = name || subagentType;
  return outputWithContext(
    `[Auto-Task] Agent "${agentLabel}" launched without a TaskCreate. ` +
    `Suggested: TaskCreate(subject="${instruction.subject}", ` +
    `activeForm="${instruction.activeForm}")`,
  );
}
